import { format, formatDistanceToNow, formatDistanceToNowStrict, parseISO } from 'date-fns';
import { formatInTimeZone, format as formatWithTz } from 'date-fns-tz';

type FormatType = 'ShortDate' | 'DateSerialized' | 'Time' | 'DateTimeSecondsTZ' | 'DaysAgo';

const getDateObj = (date: Date | string) =>
  typeof date === 'string' ? parseISO(date) : new Date(date);

/**
 * Formats date to predefined formats
 * @param {Date | String} date Date to be formatted
 * @param {FormatType | String} outputFormat Expected format
 * @return {String} date formatted
 */
export const formatDate = (
  date: Date | string,
  outputFormat: FormatType | string,
  fallback?: string,
  timeZone?: string
): string => {
  if (!date) {
    return fallback || 'N/A';
  }

  try {
    const dateObj = getDateObj(date);

    switch (outputFormat) {
      case 'ShortDate':
        return format(dateObj, 'P');
      case 'DateSerialized':
        return format(dateObj, 'yyyy-MM-dd');
      case 'Time':
        return format(dateObj, 'p');
      case 'DaysAgo':
        return formatDistanceToNowStrict(dateObj, { addSuffix: true, unit: 'day' });
      case 'TimeAgo':
        return formatDistanceToNow(dateObj, { addSuffix: true });
      case 'DateTimeSecondsTZ':
        // note that we're getting locale as en-US via default date-fns behavior
        // in future, we may want to pass in other locale options
        return formatWithTz(dateObj, 'yyyy/MM/dd hh:mm:ss aa zzz');
      case 'ShortDateTZ':
        return formatInTimeZone(dateObj, timeZone || '', 'MM/dd/yyyy');
      default:
        return format(dateObj, outputFormat);
    }
  } catch (_err) {
    console.warn(`unable to parse date ${date?.toString()}`);
  }

  return 'Invalid Date';
};

// All admin/staff views should show dates in Central time
export const formatAdminDate = (date: Date | string, outputFormat: FormatType | string) => {
  try {
    const dateObj = getDateObj(date);

    switch (outputFormat) {
      case 'DaysAgo':
        return formatDistanceToNowStrict(dateObj, { addSuffix: true, unit: 'day' });
      case 'TimeAgo':
        return formatDistanceToNow(dateObj, { addSuffix: true });
      case 'DateTimeSeconds':
        return formatInTimeZone(dateObj, 'America/Chicago', 'MM/dd/yyyy hh:mm:ss aa');
      case 'DateTimeSecondsTZ':
        return formatInTimeZone(dateObj, 'America/Chicago', 'MM/dd/yyyy hh:mm:ss aa zzz');
      case 'ShortDateTZ':
        return formatInTimeZone(dateObj, 'America/Chicago', 'MM/dd/yyyy');
      default:
        return formatInTimeZone(dateObj, 'America/Chicago', outputFormat);
    }
  } catch {
    console.warn(`unable to parse date ${date?.toString()}`);
  }

  return 'Invalid Date';
};

