export const LiveFinancePreview = () => {
  const { funds } = useGetAllFundsIncludingIncoming();
  const { watch } = useFormContext<ActionPageDetailFormValues>();
  const formFundSelections = watch('fundConfiguration.fundSelectionsAttributes');
  const amountPresetsOther = watch('amountConfiguration.amountPresetsOther');
  const multiFundExpanded = watch('fundConfiguration.multiFundExpanded');
  const multiFundModifiable = watch('fundConfiguration.multiFundModifiable');
  const fundGroups = watch('fundConfiguration.fundGroupsAttributes');

  const amounts = watch('amountConfiguration.amountPresets.default')?.map((amount) => ({
    ...amount,
    amount: formatCurrency(currency(amount.amount!).intValue, { hideDecimal: true }),
  }));

  const selectedFunds = getFundSelections(funds, formFundSelections, true).filter(
    (f) => !f._destroy
  );

  const additionalFunds = multiFundModifiable
    ? getFundSelections(funds, formFundSelections, false).filter((f) => !f._destroy)
    : [];

  const formRecurringOptions = watch('amountConfiguration.recurringOptions');
  const goaaEnabled = watch('goaaEnabled');
  const goaaMinimumAmount = watch('goaaMinimumAmount');
  const productsForRecurringOnly = watch('productsForRecurringOnly');
  const goaaForceSelection = watch('goaaForceSelection');
  const recurringMessage = watch('amountConfiguration.recurringMessage');

  const frequencies = useMemo(
    () => formRecurringOptions?.map((option) => option) || [],
    [formRecurringOptions]
  );

  const [selectedFrequency, setSelectedFrequency] = useState<SourceFrequency>(frequencies[0]);
  const [selectedAmount, setSelectedAmount] = useState<ActionPageFinancePreset | null>(null);
  const [otherAmount, setOtherAmount] = useState<string>();

  const form = useEnhancedForm({ initialValues: { email: '', name: '' } });
