  const futurePledgeDateValue = watch('amountConfiguration.futurePledgeDate');

  const futurePledgeDate = useMemo(
    () =>
      futurePledgeDateValue instanceof Date
        ? futurePledgeDateValue?.toISOString()
        : futurePledgeDateValue,
    [futurePledgeDateValue]
  );

  const futurePledgeMessage = watch('amountConfiguration.futurePledgeMessage');

  return (
    <FormProvider {...form}>
      <DonationSelector
        additionalFunds={additionalFunds}
        amountAllocations={[]}
        amountPresetsOther={amountPresetsOther}
        amounts={amounts}
        frequencies={frequencies}
        fundGroups={fundGroups ?? []}
        funds={selectedFunds}
        futurePledgeDate={futurePledgeDate}
