import { useGetAccount } from '@state/accounts';
import { parseDate } from '@ui/utils/parseDate';
import { format, parseISO } from 'date-fns';
import { formatInTimeZone, getTimezoneOffset } from 'date-fns-tz';
import { useCallback } from 'react';

type DateArg = Date | number | string;

export const useDateFormat = () => {
  const { currentAccount } = useGetAccount();

  const timeZone = currentAccount?.timeZone;
  const currentYear = new Date().getFullYear();
  const timeZoneOffset = !!timeZone && getTimezoneOffset(timeZone, new Date(currentYear, 1, 1));
  const isValidTimezone = !!timeZone && !Number.isNaN(timeZoneOffset);

  const conditionalFormat = useCallback(
    (date: DateArg, formatStr: string) => {
      try {
        const dateObj = typeof date === 'string' ? parseISO(date) : new Date(date);
        return isValidTimezone
          ? formatInTimeZone(date, timeZone, formatStr)
          : format(dateObj, formatStr);
      } catch (_err) {
        console.warn(`unable to parse date ${date?.toString()}`);
      }

      return 'Invalid Date';
    },
    [isValidTimezone, timeZone]
  );

  const formatInterval = useCallback(
    (startDate: DateArg, endDate: DateArg) => {
      try {
        const startDateObj = parseDate(startDate);
        const endDateObj = parseDate(endDate);

        if (isValidTimezone) {
          const [startDay, startMonth, startYear] = formatInTimeZone(
            startDateObj,
            timeZone,
            'dd-mm-yyyy'
          ).split('-');
          const [endDay, endMonth, endYear] = formatInTimeZone(
            endDateObj,
            timeZone,
            'dd-mm-yyyy'
          ).split('-');

          const sameDay = startDay === endDay;
          const sameMonth = startMonth === endMonth;
          const sameYear = startYear === endYear;

          if (sameDay && sameMonth && sameYear) {
            return formatInTimeZone(startDate, timeZone, 'PP');
          }

          if (sameMonth && sameYear) {
            return `${formatInTimeZone(startDate, timeZone, 'MMM d')}-${formatInTimeZone(
              endDate,
              timeZone,
              'd, Y'
            )}`;
          }

          if (sameYear) {
            return `${formatInTimeZone(startDate, timeZone, 'MMM d')} - ${formatInTimeZone(
              endDate,
              timeZone,
              'MMM d, Y'
            )}`;
          }

          return `${formatInTimeZone(startDate, timeZone, 'PP')} - ${formatInTimeZone(
            endDate,
            timeZone,
            'PP'
          )}`;
        }
      } catch (_err) {
        console.warn(`unable to parse interval`);
      }

      return 'Invalid Date';
    },
    [isValidTimezone, timeZone]
  );

  return { format: conditionalFormat, formatInterval };
};

